export const scrollToId = (id: string) => {
  const targetElement = document.querySelector(`section#${id}`);
  if (targetElement) {
    targetElement.scrollIntoView({ behavior: 'smooth', block: 'start' });
    // Opcional: Actualizar el hash de la URL para mantener la consistencia
    window.history.pushState(null, '', `#${id}`);
  }
};

// Ejemplo para un enlace en el Header (aplicar a todos los afectados, desktop y móvil)
<a
  href="#como-funciona"
  onClick={(e) => {
    e.preventDefault(); // Previene el scroll por defecto del navegador
    scrollToId('como-funciona');
  }}
>
  Cómo funciona
</a>
